inline const uint16_t* aircraftBitmap(AircraftBitmapId id) {
  switch (id) {
    case AircraftBitmapId::AIRLINER: return AIRCRAFT_BITMAP_AIRLINER;
    case AircraftBitmapId::BUSINESS_JET: return AIRCRAFT_BITMAP_BUSINESS_JET;
    case AircraftBitmapId::TURBOPROP: return AIRCRAFT_BITMAP_TURBOPROP;
    case AircraftBitmapId::PISTON: return AIRCRAFT_BITMAP_PISTON;
    case AircraftBitmapId::HELICOPTER: return AIRCRAFT_BITMAP_HELICOPTER;
    default: return AIRCRAFT_BITMAP_UNKNOWN;
  }
}
